import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"如何通过 PayNow 入金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/sg-methods/paynow.md","filePath":"zh-CN/deposit/sg-methods/paynow.md"}'),d={name:"deposit/sg-methods/paynow.md"};function i(l,t,s,n,h,p){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="如何通过-paynow-入金" tabindex="-1">如何通过 PayNow 入金 <a class="header-anchor" href="#如何通过-paynow-入金" aria-label="Permalink to &quot;如何通过 PayNow 入金&quot;">​</a></h1><p>PayNow 是新加坡的实时电子转账服务，支持通过手机号码、身份证/FIN 号码、UEN 或二维码进行即时资金转账。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>新加坡元（SGD）</td></tr><tr><td>到账时间</td><td>实时，最快 5 分钟；扫码时未填备注则需人工匹配，预计 3 个工作日</td></tr><tr><td>手续费</td><td>免费</td></tr></tbody></table><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>打开长桥 App，进入<strong>资产 → 全部功能 → 存入资金 → SGD → PayNow</strong>，生成收款二维码</li><li>打开手机银行，扫描二维码，填写备注内容，完成付款</li></ol><p>无需上传入金凭证。</p><h2 id="备注填写要求与同名账户限制" tabindex="-1">备注填写要求与同名账户限制 <a class="header-anchor" href="#备注填写要求与同名账户限制" aria-label="Permalink to &quot;备注填写要求与同名账户限制&quot;">​</a></h2><ul><li><strong>必须填写备注</strong>：扫码时未填备注，需人工匹配，到账时间延长至 3 个工作日</li><li>一个二维码只能扫一次；重复扫码不会丢失资金，但需人工匹配</li><li>如长桥开户名与银行支付名不一致，需人工核实，到账时间会延长</li><li>PayNow 不支持出金</li></ul>',8)])])}const m=a(d,[["render",i]]);export{c as __pageData,m as default};
